        <Button variant="outline" className="bg-white hover:bg-neutral-100" onClick={handleBack}>
          <ArrowLeft className="w-4 h-4 mr-2" />
          {quoteId ? "詳細に戻る" : "一覧に戻る"}
        </Button>
        <Button onClick={() => window.print()}>
