          customerName={data.customerName}
          totalA={data.totalA}
          totalB={data.totalB}
          totalC={data.totalC}
          grandTotal={data.grandTotal}
          itemsA={data.itemsA || []}
          itemsB={data.itemsB || []}
          itemsC={data.itemsC || []}
        />
      </div>

      <style dangerouslySetInnerHTML={{
        __html: `
        @media print {
          html, body {
            margin: 0 !important;
            padding: 0 !important;
            background: white !important;
            -webkit-print-color-adjust: exact !important;
            print-color-adjust: exact !important;
