              />
            </div>
            <div className="w-20">
              {index === 0 && <Label className="text-xs text-gray-400 mb-1 block">数量</Label>}
              <Input 
                type="number" 
                value={item.qty || ''} 
                onChange={(e) => updateItem(item.id, 'qty', Number(e.target.value))} 
              />
            </div>
            <div className="w-28 text-right pt-2 md:pt-6 font-medium text-gray-700">
              ¥{(item.price * item.qty).toLocaleString()}
            </div>
            <div className={index === 0 ? "pt-5" : ""}>
              <Button 
                type="button" 
                variant="ghost" 
                size="icon" 
                className="text-red-500 hover:text-red-700 hover:bg-red-50"
                onClick={() => removeItem(item.id)}
              >
                <Trash2 className="w-4 h-4" />
              </Button>
            </div>
          </div>
        ))}
        {items.length === 0 && (
          <p className="text-sm text-gray-500 text-center py-4 border rounded-md border-dashed">
            明細行がありません
          </p>
        )}
      </div>

      <div className="pt-4 border-t flex justify-end">
        <div className="text-right">
          <p className="text-sm text-gray-500 mb-1">小計 (C)</p>
          <p className="text-2xl font-bold text-orange-800">¥{total.toLocaleString()}</p>
        </div>
      </div>
    </div>
  )
})

import { createClient } from "@libsql/client";
import { drizzle } from "drizzle-orm/libsql";
import { quotes } from "./schema";
import { isNull, or, eq } from "drizzle-orm";

import dotenv from "dotenv";
dotenv.config({ path: ".env.local" });

const turso = createClient({
    url: process.env.TURSO_DATABASE_URL!,
    authToken: process.env.TURSO_AUTH_TOKEN,
});
const db = drizzle(turso);

const subjectPool = [
    "シロアリ駆除工事一式",
    "床下防処理およびシロアリ駆除の件",
    "ゴキブリ防除工事",
    "ネズミ駆除（定期契約）",
    "ハチ駆除及び巣穴封鎖工事",
    "床下海水処理およびシロアリ防除",
    "川底消毒工事",
    "ネズミ駆除一式",
    "ペット身振り叮防除工事",
    "シロアリ防除及び床板張替工事",
    "川底消毒および防蛙工事",
    "床下改修およびシロアリ駆除工事",
    "子供室カカル駆除工事",
    "洗面台まわり防除工事",
    "防蛙一式および坂駆除工事",
    "床下シロアリ・ネズミ点検調査",
    "厨房消毒えこキ工事",
    "コウモリ駆除及び工事",
    "和室床下散布工事",
    "床下シロアリ工事及び消毒一式",
];

async function main() {
    try {
        console.log("Fetching all quotes without subject...");
        const allQuotes = await db.select({ id: quotes.id, subject: quotes.subject }).from(quotes);
        const nullSubjects = allQuotes.filter(q => !q.subject);

        console.log(`Found ${nullSubjects.length} quotes without subject. Updating...`);

        for (let i = 0; i < nullSubjects.length; i++) {
            const subject = subjectPool[i % subjectPool.length];
            await db.update(quotes)
                .set({ subject })
                .where(eq(quotes.id, nullSubjects[i].id));
        }

        console.log(`Updated ${nullSubjects.length} quotes with subjects!`);
    } catch (error) {
        console.error("Error:", error);
    } finally {
        process.exit(0);
    }
}

main();

import { createClient } from "@libsql/client";
import { drizzle } from "drizzle-orm/libsql";
import { items } from "./schema";
import fs from "fs";
import path from "path";
import { parse } from "csv-parse/sync";

// 環境変数の読み込み(.env.localがあれば)
import dotenv from "dotenv";
dotenv.config({ path: ".env.local" });

const turso = createClient({
    url: process.env.TURSO_DATABASE_URL!,
    authToken: process.env.TURSO_AUTH_TOKEN,
});

const db = drizzle(turso);

// CSVファイルのパス
const csvFilePath = path.join(process.cwd(), "..", "my-web", "駆除業務_施工品目マスタ.csv");

async function main() {
    try {
        console.log("Reading CSV file...");
        const csvData = fs.readFileSync(csvFilePath, "utf8");

        console.log("Parsing CSV data...");
        const records = parse(csvData, {
            columns: true,
            skip_empty_lines: true,
        });

        console.log(`Found ${records.length} records. Inserting into db...`);

        const itemsToInsert = records.map((record: any) => {
            // 単価のパース処理: "7,000" -> 7000, "-" -> null
            let unitPrice = null;
            if (record["単価"] && record["単価"] !== "-") {
                const parsedPrice = parseInt(record["単価"].replace(/,/g, ""), 10);
                if (!isNaN(parsedPrice)) {
                    unitPrice = parsedPrice;
                }
            }

            // UUID生成用にcryptoは使わず、新しいID（UUID）を割り当てるようユーザーから指示があった。
            // 新規にUUIDを設定して生成する。
            const newId = crypto.randomUUID();

            return {
                id: newId,
                category: record["カテゴリー"],
                name: record["品目名（施工・商品名）"],
                unitPrice: unitPrice,
                unit: record["単位"],
                remarks: record["備考・仕様"] || null,
                createdAt: new Date(),
            };
        });

        // 既存のitemsを削除してからインポートするか、ここでは追記か
        // seedスクリプトなので、既存レコードのリセットは行わずとりあえず追加
        // しかし同じレコードが重複しないようにするなら一旦消す方が安全（要件次第だが今回はシンプルにinsert）

        // 分割してインサート (SQLite制限回避のため)
        const chunkSize = 50;
        for (let i = 0; i < itemsToInsert.length; i += chunkSize) {
            const chunk = itemsToInsert.slice(i, i + chunkSize);
            await db.insert(items).values(chunk);
        }

        console.log("Successfully seeded items data!");
    } catch (error) {
        console.error("Error seeding items:", error);
    } finally {
        process.exit(0);
    }
}

main();
